import java.util.*;
public class TestClassToString {
    public static void main(String[] args) {
        Class<?> clazz = String.class;
        System.out.println("Class.toString() = '" + clazz.toString() + "'");
        System.out.println("Class.getName() = '" + clazz.getName() + "'");
        System.out.println("Class.getSimpleName() = '" + clazz.getSimpleName() + "'");

        // Test what the expected output should be according to the test
        String expected = "java.lang.String";
        System.out.println("Expected according to test: '" + expected + "'");
        System.out.println("Does toString() match expected? " + clazz.toString().equals(expected));
        System.out.println("Does getName() match expected? " + clazz.getName().equals(expected));
    }
}

